import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const ProfilePage = () => {
  const { user, setUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [username, setUsername] = useState(user?.username || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [pic, setPic] = useState(null);
  const [preview, setPreview] = useState(null);
  const [curPw, setCurPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [showPw, setShowPw] = useState(false);
  const [toast, setToast] = useState({ msg: '', type: '' });
  const [darkMode, setDarkMode] = useState(false);

  /* ================= THEME ================= */
  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  /* ================= TOAST AUTO HIDE ================= */
  useEffect(() => {
    if (!toast.msg) return;
    const timer = setTimeout(() => setToast({ msg: '', type: '' }), 3000);
    return () => clearTimeout(timer);
  }, [toast]);

  /* ================= PROFILE UPDATE ================= */
  const handleProfile = async (e) => {
    e.preventDefault();

    const fd = new FormData();
    fd.append('name', name);
    fd.append('bio', bio);
    fd.append('username', username);
    if (pic) fd.append('profilePic', pic);

    try {
      const { data } = await API.put('/auth/profile', fd);
      setUser(data);
      setToast({ msg: 'Profile updated successfully!', type: 'success' });
    } catch (err) {
      setToast({ msg: err.response?.data?.message || 'Error updating profile', type: 'error' });
    }
  };

  /* ================= PASSWORD UPDATE ================= */
  const handlePassword = async (e) => {
    e.preventDefault();

    try {
      await API.put('/auth/change-password', {
        currentPassword: curPw,
        newPassword: newPw,
      });

      setToast({ msg: 'Password changed successfully!', type: 'success' });
      setCurPw('');
      setNewPw('');
    } catch (err) {
      setToast({ msg: err.response?.data?.message || 'Error changing password', type: 'error' });
    }
  };

  /* ================= IMAGE PREVIEW ================= */
  const handleFileChange = (file) => {
    setPic(file);
    if (file) {
      setPreview(URL.createObjectURL(file));
    }
  };

  const picSrc = preview
    ? preview
    : user?.profilePic
    ? `http://localhost:5000/uploads/${user.profilePic}`
    : '/default-avatar.png';

  /* ================= STYLES ================= */
  const styles = {
    page: {
      background: darkMode ? "#560032" : "#FAE8ED",
      minHeight: '100vh',
      padding: '40px 20px',
      display: 'flex',
      justifyContent: 'center',
    },

    container: {
      width: '100%',
      maxWidth: '750px',
      display: 'flex',
      flexDirection: 'column',
      gap: '20px',
    },

    card: {
      background: darkMode ? "#2e091e" : "#fff",
      borderRadius: '20px',
      padding: '25px',
      boxShadow: "0 10px 25px rgba(0,0,0,0.1)",
    },

    header: {
      textAlign: "center",
    },

    profilePic: {
      width: '120px',
      height: '120px',
      borderRadius: '50%',
      objectFit: 'cover',
      marginBottom: "10px",
      border: "3px solid #fff",
    },

    username: {
      fontWeight: "bold",
      fontSize: "18px",
    },

    bio: {
      fontSize: "14px",
      opacity: 0.7,
    },

    title: {
      fontWeight: "bold",
      marginBottom: "15px",
      fontSize: "16px",
    },

    input: {
      width: "100%",
      padding: "12px",
      borderRadius: "10px",
      border: "1px solid #ccc",
      marginBottom: "12px",
      outline: "none",
    },

    textarea: {
      width: "100%",
      padding: "12px",
      borderRadius: "10px",
      border: "1px solid #ccc",
      marginBottom: "12px",
    },

    fileRow: {
      display: "flex",
      alignItems: "center",
      justifyContent: "space-between",
      marginBottom: "10px",
      gap: "10px",
    },

    passwordRow: {
      position: "relative",
      marginBottom: "12px",
    },

    toggle: {
      position: "absolute",
      right: "12px",
      top: "50%",
      transform: "translateY(-50%)",
      cursor: "pointer",
      fontSize: "12px",
      color: "#888",
    },

    button: {
      width: "100%",
      padding: "12px",
      borderRadius: "10px",
      border: "none",
      cursor: "pointer",
      fontWeight: "bold",
      backgroundColor: darkMode ? "#c46392" : "#0c4b34",
      color: "#fff",
    },

    toast: {
      position: "fixed",
      top: "20px",
      right: "20px",
      padding: "12px 18px",
      borderRadius: "10px",
      color: "#fff",
      backgroundColor: toast.type === "success" ? "#16a34a" : "#dc2626",
      boxShadow: "0 5px 15px rgba(0,0,0,0.2)",
      zIndex: 999,
      transition: "all 0.3s ease",
    },
  };

  return (
    <div style={styles.page}>
      {toast.msg && <div style={styles.toast}>{toast.msg}</div>}

      <div style={styles.container}>

        {/* PROFILE CARD */}
        <div style={styles.card}>
          <div style={styles.header}>
            <img src={picSrc} alt="Profile" style={styles.profilePic} />
            <div style={styles.username}>@{user?.username}</div>
            <div style={styles.bio}>{user?.bio || "No bio yet."}</div>
          </div>
        </div>

        {/* EDIT PROFILE */}
        <form style={styles.card} onSubmit={handleProfile}>
          <div style={styles.title}>Edit Profile</div>

          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Display name"
            style={styles.input}
          />

          <input
            value={user?.email || ""}
            disabled
            style={styles.input}
          />

          <input
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            placeholder="Username"
            style={styles.input}
          />

          <textarea
            value={bio}
            onChange={(e) => setBio(e.target.value)}
            rows={3}
            style={styles.textarea}
          />

          <div style={styles.fileRow}>
            <input
              type="file"
              onChange={(e) => handleFileChange(e.target.files[0])}
            />
            <span>{pic ? pic.name : "No file chosen"}</span>
          </div>

          <button type="submit" style={styles.button}>
            Save Profile
          </button>
        </form>

        {/* PASSWORD */}
        <form style={styles.card} onSubmit={handlePassword}>
          <div style={styles.title}>Change Password</div>

          <div style={styles.passwordRow}>
            <input
              type={showPw ? "text" : "password"}
              placeholder="Current password"
              value={curPw}
              onChange={(e) => setCurPw(e.target.value)}
              style={styles.input}
            />
            <span style={styles.toggle} onClick={() => setShowPw(!showPw)}>
              {showPw ? "Hide" : "Show"}
            </span>
          </div>

          <div style={styles.passwordRow}>
            <input
              type={showPw ? "text" : "password"}
              placeholder="New password"
              value={newPw}
              onChange={(e) => setNewPw(e.target.value)}
              style={styles.input}
            />
          </div>

          <button type="submit" style={styles.button}>
            Change Password
          </button>
        </form>

      </div>
    </div>
  );
};

export default ProfilePage;
